from pydantic import BaseModel, field_validator
from typing import Optional

class AgentOutput(BaseModel):
    result: str
    confidence: float
    metadata: dict

    @field_validator("confidence")
    @classmethod
    def confidence_range(cls, v: float) -> float:
        if not 0.0 <= v <= 1.0:
            raise ValueError(f"confidence must be 0-1, got {v}")
        return v

# Every boundary requires this kind of explicit contract
# In a single-agent system, the LLM implicitly passes state
# In a multi-agent system, you write and maintain these schemas
class AgentInput(BaseModel):
    context: str
    task: str
    prior_output: Optional[AgentOutput] = None

from langgraph.graph import StateGraph, END
from typing import TypedDict

class PipelineState(TypedDict):
    raw_data: str
    extracted_facts: list[str]
    report: str
    validation_passed: bool

def validation_node(state: PipelineState) -> dict:
    """Guard: verify extracted facts before passing to report writer."""
    from langchain_anthropic import ChatAnthropic
    llm = ChatAnthropic(model="claude-haiku-4-5-20251001")

    facts_text = "\n".join(state["extracted_facts"])
    check = llm.invoke(
        f"Do these facts appear to be factually coherent and non-contradictory? "
        f"Reply YES or NO only:\n{facts_text}"
    ).content.strip().upper()

    return {"validation_passed": check.startswith("YES")}

def report_writer(state: PipelineState) -> dict:
    if not state["validation_passed"]:
        return {"report": "ERROR: upstream facts failed validation"}
    from langchain_anthropic import ChatAnthropic
    llm = ChatAnthropic(model="claude-sonnet-5")
    report = llm.invoke(
        f"Write a report from these facts:\n" +
        "\n".join(state["extracted_facts"])
    ).content
    return {"report": report}
